var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"불러 주셔서 감사합니다, 그레이스 님. 오늘도 이 한 몸 불태워 안전하게 모십지요!","JPN":"お声をかけてくださってありがとうございます、グレース様。今日もこの私めが、体を張って安全にご案内いたしましょう！","ENG":"Thank you for calling me again, Dame Grace! I'll give it my all to get you there safely!","TWN":"感謝你的召喚，葛瑞絲小姐。今天我也會燃燒自己，確保你的安全！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이쪽이야말로 잘 부탁드립니다, 클링턴 씨.","JPN":"こちらこそよろしくお願いいたします、クリントンさん。","ENG":"The pleasure is mine, Mr. Clinton.","TWN":"這邊才是要請多關照了，克林頓先生。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 영애 분도 잘 부탁드려요.","JPN":"ふふ。ご令嬢もよろしくお願いいたします。","ENG":"Haha. Milady, I'm counting on you.","TWN":"呵呵，也請馬千金多關照囉。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"결혼했습니다!","JPN":"つがいができました！","ENG":"She's married now!","TWN":"牠結婚了！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 어쩐지 성숙해졌다 싶더니.","JPN":"まあ。どうりで大人っぽくなったと思いました。","ENG":"Oh? No wonder she seems more mature.","TWN":"哎呀。難怪覺得變成熟了呢。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……또, 이 마부의 마차를 타는 겁니까?","JPN":"……また、この御者の馬車に乗るのですか？","ENG":"...Are we seriously riding with this coachman again?","TWN":"……又要坐這馬車夫的馬車嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"클링턴 씨는 제국 내에서도 손꼽히는 마부이십니다.","JPN":"クリントンさんは帝国でも有名な御者なのです。","ENG":"Mr. Clinton is one of the finest coachmen in the Empire.","TWN":"克林頓先生是帝國內數一數二的馬夫。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"위험도가 높은 원정에 이보다 제격인 분이 어디 있겠습니까?","JPN":"危険度の高い遠征に、彼より相応しい方はいません。","ENG":"For an expedition this dangerous, you won't find a better choice.","TWN":"還有誰比你更適合高風險的遠征呢？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"흔들림이 걱정되신다면 손잡이를 배치해드릴까요?","JPN":"揺れが心配でしたら、手すりを設置しましょうか？","ENG":"If you're worried about the bumps, I can have a handrail installed.","TWN":"如果你擔心晃動的話，要不要給你裝一個扶手？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"괜찮습니다.","JPN":"結構です。","ENG":"No need.","TWN":"沒關係。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 문제가 없다면 이만 출발하지요.","JPN":"ふふ。問題がなければ出発しましょう。","ENG":"Haha. If there's nothing else, then let's be off.","TWN":"呵呵。如果沒有問題的話，那我們就出發吧。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부인. 잠시 괜찮으십니까?","JPN":"夫人。よろしいですか？","ENG":"Ma'am. Do you have a moment?","TWN":"夫人，打擾一下？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"여쭤볼 게 있습니다만…….","JPN":"聞きたいことがあるのですが……","ENG":"There's something I'd like to ask...","TWN":"我有件事想問……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 지난번에 못한 <color=#ffd34c>질문</color>을 하실 생각이 드셨습니까?","JPN":"あら。先日果たせなかった<color=#ffd34c>質問</color>のことでしょうか？","ENG":"Oh my. Have you finally decided to ask the <color=#ffd34c>question</color> you couldn't last time?","TWN":"那是<color=#ffd34c>問題</color>嗎?"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"농담입니다. 대답하기 곤란한 것을 제외하곤 답변해드릴 터이니, 편히 말씀해 보시지요.","JPN":"冗談です。答えづらいことでなければお答えしますので、お気楽にどうぞ。","ENG":"I'm joking. Unless it's something I truly can't answer, I'll do my best. Go ahead.","TWN":"開玩笑的。除了無法回答的問題，我會儘量回答的，請隨意提問吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"별건 아니고, 병력의 이동 대형이 조금 의아했을 뿐입니다.","JPN":"大したことではないのですが、兵力の移動隊形が少しおかしいと思ったのです。","ENG":"It's nothing major, I was just curious about the formation.","TWN":"沒什麼，只是部隊的移動陣型有些奇怪而已。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"현재의 방진은 장기 기동에 적합한 전술로는 보이지 않는군요.","JPN":"現在の方陣は長期の機動に適合しているようには思えません。","ENG":"It doesn't look suited for long-range movement.","TWN":"目前的陣型似乎不適合長時間機動的戰術。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"타당한 지적입니다. 전술적으로 봤을 때 팔랑크스는 수세적인 진법에 가깝지요.","JPN":"正しい指摘です。戦術的な観点からすれば、ファランクスは守りを重視した陣形に近いです。","ENG":"A valid point. Tactically, a phalanx is a defensive formation.","TWN":"這是一個合理的疑問。從戰術上看，方陣更接近於防禦陣型。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나 병사들의 본분이 제 호위임을 생각하면, 현 상황에서는 유효한 진법입니다.","JPN":"ですが、兵士たちの本分が私の護衛であることを考えると、今の状況では有効な陣形なのです。","ENG":"But considering the soldiers are here to guard me, it's the best fit for our current situation.","TWN":"不過考慮到士兵們的職責是護衛我，在當前情況下，這是一種有效的陣法。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지킨다? 이 병사들이 전부 말입니까?","JPN":"守る？　この数の兵士全員がですか？","ENG":"Guard you? All of them?","TWN":"保護嗎？這些士兵全都是嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"대체 무엇으로부터-.","JPN":"いったい何から……","ENG":"Guard you from wh–","TWN":"究竟從何而來-"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"모두 정지! 전방에 대량의 괴수가 나타났다!","JPN":"全員、止まれ！　前方に大量の怪獣が現れた！","ENG":"All units, halt! Large group of C.O.s spotted ahead!","TWN":"全部停下！前方出現大量怪物！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CAR_SHAKE"},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"무기를 갖추고 전투에 대비하라! 놈들이 접근하기 전에 선수를 친다!!","JPN":"武器を構え、戦闘に備えよ！　やつらが近づく前に先手を打つ！","ENG":"Ready your weapons! Engage before they reach us!","TWN":"準備武器，迎戰！在他們接近之前先發制人！！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"침식체라니… 분명 안전한 곳으로만 이동한다고 들었는데 이상하군요.","JPN":"侵食体……？　安全な道を選んで移動すると聞いたのですが、おかしいですね。","ENG":"C.O.s...? I was told we'd be traveling through safe zones. This is odd.","TWN":"竟然是侵蝕體……明明聽說只會移動到安全的地方，真是奇怪啊。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"지천을 배회하는 괴수는 자신이 품지 못한 가능성을 찾아 헤매는 존재입니다.","JPN":"至るところを徘徊する怪獣は、自分にはない可能性を探し回る存在。","ENG":"C.O.s wander in search of potential they couldn't hold onto.","TWN":"徘徊在天際的怪獸，是尋找自己無法擁有的可能性的存在。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이곳에 강렬한 별빛이 있으니, 걸신들리듯 모여드는 것도 이상하지 않지요.","JPN":"ここに強烈な星の光があるので、その欲を満たそうと押し寄せて来てもおかしくありません。","ENG":"And with such a strong starlight presence here, of course they'd be drawn in like moths to a flame.","TWN":"這裡有強烈的星光，所以聚集過來也不足為奇。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"페론 경. 상황 보고를 부탁드립니다.","JPN":"ペロン卿、状況の報告を。","ENG":"Sir Ferron. Give me a status report.","TWN":"費隆卿。請彙報情況。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"전방 1km가량의 거리에서 짐승형과 비행형의 괴수들이 무리를 이루고 있습니다.","JPN":"前方1km程の距離に、野獣型と飛行型の怪獣が群れを成しています。","ENG":"Packs of beasts and flying C.O.s moving together roughly a mile ahead.","TWN":"前方約1公里處有獸型和飛行型怪物成群結隊。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"수가 많지는 않으나, 대다수가 비행형이기에 거리를 벌려 대처하는 것이 좋겠군요.","JPN":"数は多くありませんが、ほとんどが飛行型であるため、距離を置いて対処した方がよさそうです。","ENG":"Their numbers aren't high, but since most are airborne, we'll need to spread out to handle them.","TWN":"數量雖然不多，但大多數是飛行型，最好拉開距離應對。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"아뇨. <color=#ffd34c>무구</color>를 사용해 일점돌파합니다.","JPN":"いいえ。<color=#ffd34c>武具</color>を使い、一点突破します。","ENG":"No. We'll break through with <color=#ffd34c>Armaments</color>.","TWN":"不。使用<color=#ffd34c>武具</color>進行單點突破。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"본대로 적의 이목을 끌어 한 점에 몰아넣을 테니.","JPN":"本隊が敵の注意を引き付け、一か所に集めますので。","ENG":"I'll draw their attention and funnel them into one spot.","TWN":"按照計畫吸引敵人的注意力，將他們集中到一個點上。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"페론 경은 무구를 사용 가능한 기사들을 이끌고 적의 측면으로 이동하시지요.","JPN":"ペロン卿は武具を扱える騎士を率いて敵の側面へと移動してください。","ENG":"Sir Ferron, lead the knights capable of using Armaments and circle around to flank them.","TWN":"費隆卿率領能夠使用武具的騎士們向敵人的側翼移動吧。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"하지만 그레이스 경. 무구의 힘을 사용했다간…….","JPN":"ですがグレース卿、武具の力を使用すると……","ENG":"But Dame Grace. If you use the Armament's power...","TWN":"但是葛瑞絲小姐，使用武具的力量的話……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"멀리 있는 침식체들의 이목이 집중될지도 모르죠.","JPN":"遠くにいる侵食体の注意まで引いてしまうかもしれませんね。","ENG":"We might draw in other C.O.s farther out.","TWN":"遠處的侵蝕體可能會被吸引過來。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나 무구를 사용하지 않는다면 병사들을 사지로 내모는 것이나 다름없습니다.","JPN":"ですが、武具を使わなければ、むざむざ兵士を死に追いやるようなものです。","ENG":"But if we don't use the Armament, we'll just be throwing our soldiers into the meat grinder.","TWN":"然而，如果不使用武具，就等於把士兵們推向絕境。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"가능성이 있다면, 조금이라도 더 살리는 쪽에 거는 것이 타당하지 않겠습니까?","JPN":"可能性があるのなら、少しでも生き残る方に賭けるのが妥当なのでは？","ENG":"If there's even a small chance to save more lives, shouldn't we take it?","TWN":"如果有可能的話，選擇讓更多人活下來不是更合理嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"예. 명령 받들겠습니다.","JPN":"はい。承知いたしました。","ENG":"Yes, understood.","TWN":"是，遵命。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무례한 부탁이 아니라면 에스텔에게는 선봉을 부탁드리고 싶군요.","JPN":"失礼でないなら、エステルには先鋒に立って欲しいのですが。","ENG":"If it's not too much to ask, I'd like to place you at the vanguard, Esther.","TWN":"如果不是無禮的請求，我希望能請艾斯特擔任先鋒。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이곳의 지휘관은 다름아닌 부인이시니 편히 부탁하셔도 됩니다.","JPN":"ここでの指揮官は他でもなく夫人ですので、気兼ねなくお命じください。","ENG":"You're the commander here, ma'am. Feel free to ask whatever you like.","TWN":"這裡的指揮官就是夫人，都聽夫人的安排。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"선봉 이외에 당부하실 건 없으십니까?","JPN":"先鋒以外にはありませんか？","ENG":"Anything else, besides leading the charge?","TWN":"除了前鋒之外，有其他我能效勞的地方嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"자고로 제국의 선봉이란 기수를 뜻하지요.","JPN":"昔から帝国の先鋒とは旗手と決まっています。","ENG":"In the Empire, leading the vanguard also means carrying the banner.","TWN":"自古以來，帝國的先鋒就等於是騎士。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경께서 괜찮으시다면, 제국의 깃발을 들고 싸워주실 수 있을는지요?","JPN":"卿さえよろしければ、帝国の旗を持って戦っていただけませんか？","ENG":"If you're willing, would you carry the Empire's flag into battle?","TWN":"如果你不介意的話，你能否舉起帝國的旗幟戰鬥呢？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"거절하겠습니다.","JPN":"お断りします。","ENG":"I'll have to decline.","TWN":"我拒絕。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후, 농담이랍니다.","JPN":"ふふ、冗談です。","ENG":"Haha, just teasing.","TWN":"呵呵，我開玩笑的。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그 외에 부탁할 것이라면… 그렇군요.","JPN":"それ以外となると……そうですね。","ENG":"If there's anything else... Hmm.","TWN":"其他能效勞的地方嗎……原來如此。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무리하지 마세요, 에스텔.","JPN":"無理はしないでください、エステル。","ENG":"Don't push yourself too much, Esther.","TWN":"我只希望你別太勉強自己，艾斯特。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"예.","JPN":"はい。","ENG":"Understood.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"받들겠습니다, 부인.","JPN":"承知いたしました、夫人。","ENG":"I'll carry out your command.","TWN":"遵命，夫人。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};